#include<iostream>
using namespace std;
long long mv,mm,n,t[4001],w[4001],k[4001],dp[4001][4001];
int main()
{
	cin>>n;

	for(int i=1;i<=n;i++)  cin>>w[i]>>k[i]>>t[i];
    cin>>mv>>mm;


	for(int i=1;i<=n;i++){
		for(int j=mv;j>=t[i];j--){
			for(int p=mm;p>=w[i];p--){
					if(dp[j - k[i]][p - w[i]] + 20000 - t[i] > dp[j][p]) {
	    		dp[j][p] = dp[j -k[i]][p - w[i]] + 20000 - t[i];
	    	}
			}
		}
	}
	cout<< ((dp[mv][mm] / 20000 + 1) * 20000) - dp[mv][mm];
	return 0;
}
